  const adminUser = await validateAdmin();
  if (!adminUser) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const body = await request.json();
    const { 
      clientId, 
      serviceEngagementId,
      negativeItemId, 
      bureau, 
      disputeReason, 
      disputeType,
      methodology,
      evidenceDocumentIds,
